INSERT INTO reviews(product_id,user_id,rating,title,body) VALUES (1,2,5,'Quiet and exceptionally clean','The 7800X3D and 4080 SUPER handle ultra settings effortlessly.'),(1,3,5,'A high-end plug-and-play PC','Fast boot times and excellent cable management.'),(2,4,5,'Rapid Trigger matters','The 0.1mm tuning feels fantastic in competitive FPS games.'),(2,3,4,'Excellent performance keyboard','Superb build quality; I would also like wireless.'),(3,2,5,'Outstanding motion clarity','360Hz at QHD is a huge upgrade for esports.');
